def _parse_json_object(text: Any) -> dict[str, Any] | None:
    raw = str(text or '').strip()
    if not raw:
        return None
    try:
        data = json.loads(raw)
    except Exception:
        start = raw.find('{')
        end = raw.rfind('}')
        if start < 0 or end <= start:
            return None
        try:
            data = json.loads(raw[start:end + 1])
        except Exception:
            return None
    return data if isinstance(data, dict) else None


